namespace sv_66871551bc6942439976de5bb2252674.Client.Services;

public sealed record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    string Location,
    DateTimeOffset Timestamp);

namespace sv_66871551bc6942439976de5bb2252674.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_66871551bc6942439976de5bb2252674.Client.Services;

namespace sv_66871551bc6942439976de5bb2252674.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", "New York, NY", new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Departed facility", "New York, NY", new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at sorting center", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 6, 15, 0, TimeSpan.Zero)),
            ]),
        ["TRK-002"] = new ShipmentDetails(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 19, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Package picked up", "Seattle, WA", new DateTimeOffset(2026, 5, 17, 8, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit", "Portland, OR", new DateTimeOffset(2026, 5, 18, 11, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 19, 7, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 19, 10, 22, 0, TimeSpan.Zero)),
            ]),
        ["TRK-003"] = new ShipmentDetails(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Label created", "Dallas, TX", new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;

namespace sv_66871551bc6942439976de5bb2252674.Client.Services;

public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_66871551bc6942439976de5bb2252674.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> —
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

